class UndergroundSystem:
    def __init__(self):
        self.check_ins = {}
        self.route_data = {}
    def checkIn(self, id, stationName, t):
        self.check_ins[id] = (stationName, t)
    def checkOut(self, id, stationName, t):
        start_station, start_time = self.check_ins.pop(id)
        key = (start_station, stationName)
        if key not in self.route_data:
            self.route_data[key] = [0, 0]
        self.route_data[key][0] += t - start_time
        self.route_data[key][1] += 1
    def getAverageTime(self, startStation, endStation):
        total, count = self.route_data[(startStation, endStation)]
        return total / count

