class UndergroundSystem:
    def __init__(self):
        self._check_ins = {}
        self._routes = {}
    def checkIn(self, id: int, stationName: str, t: int) -> None:
        self._check_ins[id] = (stationName, t)
    def checkOut(self, id: int, stationName: str, t: int) -> None:
        src, t0 = self._check_ins.pop(id)
        key = (src, stationName)
        entry = self._routes.get(key)
        if entry is None:
            self._routes[key] = [t - t0, 1]
        else:
            entry[0] += t - t0
            entry[1] += 1
    def getAverageTime(self, startStation: str, endStation: str) -> float:
        total, cnt = self._routes[(startStation, endStation)]
        return total / cnt

