var UndergroundSystem = function() {
    this.checkIns = {};
    this.routes = {};
};
UndergroundSystem.prototype.checkIn = function(id, stationName, t) {
    this.checkIns[id] = [stationName, t];
};
UndergroundSystem.prototype.checkOut = function(id, stationName, t) {
    const [src, t0] = this.checkIns[id];
    delete this.checkIns[id];
    const key = src + '|' + stationName;
    if (!this.routes[key]) this.routes[key] = [0, 0];
    this.routes[key][0] += t - t0;
    this.routes[key][1] += 1;
};
UndergroundSystem.prototype.getAverageTime = function(startStation, endStation) {
    const [total, cnt] = this.routes[startStation + '|' + endStation];
    return total / cnt;
};
